#include <bits/stdc++.h>
using namespace std;

int n, r;
bool used[25];
vector<int> ans;

void DFS(int p, int a) {
    if (p > r) {
        for (int i : ans)
            printf("%3d", i);
        printf("\n");
        return ;
    }
    for (int i = a; i <= n; i++) {
        if (!used[i]) {
            used[i] = true;
            ans.push_back(i);
            DFS(p + 1, i + 1);
            used[i] = false;
            ans.pop_back();
        }
    }
}

int main() {
    cin >> n >> r;
    DFS(1, 1);
    return 0;
}
